```

**Dias 2-4: Escrever testes unitários**

```typescript
// task-policy.test.ts
import { describe, it, expect } from 'vitest';
import { TaskCompletionPolicy } from './task-policy';

describe('TaskCompletionPolicy', () => {
  it('deve rejeitar task não encontrada', () => {
    const result = TaskCompletionPolicy.canComplete(null, 1);
    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error).toBe('TASK_NOT_FOUND');
    }
  });

  it('deve rejeitar task já completada', () => {
    const task = { id: 1, completed: true, ownerId: 1, estimateHours: 5 };
    const result = TaskCompletionPolicy.canComplete(task, 1);
    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error).toBe('TASK_ALREADY_COMPLETED');
    }
  });

  it('deve rejeitar usuário não autorizado', () => {
    const task = { id: 1, completed: false, ownerId: 1, estimateHours: 5 };
    const result = TaskCompletionPolicy.canComplete(task, 999);
    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error).toBe('UNAUTHORIZED');
    }
  });

  it('deve rejeitar estimativa inválida', () => {
    const task = { id: 1, completed: false, ownerId: 1, estimateHours: -1 };
    const result = TaskCompletionPolicy.canComplete(task, 1);
    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error).toBe('INVALID_ESTIMATE');
    }
  });

  it('deve permitir conclusão válida', () => {
    const task = { id: 1, completed: false, ownerId: 1, estimateHours: 5 };
    const result = TaskCompletionPolicy.canComplete(task, 1);
    expect(result.success).toBe(true);
  });
});
```

```typescript
// complete-task-use-case.test.ts
import { describe, it, expect, vi } from 'vitest';
import { CompleteTaskUseCase } from './complete-task-use-case';

describe('CompleteTaskUseCase', () => {
  it('deve completar task com sucesso', async () => {
    const mockRepo = {
      findById: vi.fn().mockResolvedValue({ id: 1, completed: false, ownerId: 1, estimateHours: 5 }),
      update: vi.fn().mockResolvedValue(undefined),
    };
    const mockAudit = { log: vi.fn().mockResolvedValue(undefined) };
    const mockClock = { now: vi.fn().mockReturnValue(new Date('2024-01-01')) };

    const useCase = new CompleteTaskUseCase(mockRepo, mockAudit, mockClock);
    const result = await useCase.execute(1, 1);

    expect(result.success).toBe(true);
    expect(mockRepo.update).toHaveBeenCalledWith(1, { completed: true, completedAt: new Date('2024-01-01') });
    expect(mockAudit.log).toHaveBeenCalledWith({ event: 'TASK_COMPLETED', taskId: 1, userId: 1, timestamp: new Date('2024-01-01') });
  });

  it('deve propagar erro de política', async () => {
    const mockRepo = {
      findById: vi.fn().mockResolvedValue({ id: 1, completed: true, ownerId: 1, estimateHours: 5 }),
      update: vi.fn(),
    };
    const mockAudit = { log: vi.fn() };
    const mockClock = { now: vi.fn().mockReturnValue(new Date('2024-01-01')) };

    const useCase = new CompleteTaskUseCase(mockRepo, mockAudit, mockClock);
    const result = await useCase.execute(1, 1);

    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error).toBe('TASK_ALREADY_COMPLETED');
    }
    expect(mockRepo.update).not.toHaveBeenCalled();
  });
});
```

**Dia 5: Medir cobertura e configurar CI/CD**
