### SEMANA 2: Refinamentos recorrentes (Prioridade ALTA)

**Dias 1-2: Logger estruturado**

```bash
npm install pino
```

```typescript
// logger.ts
import pino from 'pino';

export const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
  transport: {
    target: 'pino-pretty',
    options: { colorize: true },
  },
});

export type Logger = typeof logger;
```

```typescript
// complete-task-use-case.ts (atualizado)
export class CompleteTaskUseCase {
  constructor(
    private readonly repository: TaskRepository,
    private readonly auditGateway: AuditGateway,
    private readonly clock: Clock,
    private readonly logger: Logger, // ✅ Adicionar logger
  ) {}

  async execute(taskId: number, userId: number): Promise<Result<void, DomainError>> {
    this.logger.info({ taskId, userId }, 'Iniciando conclusão de task');

    const task = await this.repository.findById(taskId);
    const validation = TaskCompletionPolicy.canComplete(task, userId);

    if (!validation.success) {
      this.logger.warn({ taskId, userId, error: validation.error }, 'Validação falhou');
      return validation;
    }

    const now = this.clock.now();
    await this.repository.update(taskId, { completed: true, completedAt: now });
    await this.auditGateway.log({ event: 'TASK_COMPLETED', taskId, userId, timestamp: now });

    this.logger.info({ taskId, userId }, 'Task completada com sucesso');
    return { success: true, data: undefined };
  }
}
```

**Dia 3: Branded types**

```typescript
