// integration/task-completion-flow.test.ts
import { describe, it, expect, beforeEach } from 'vitest';
import { InMemoryTaskRepository } from '../tasks/in-memory-task-repository';
import { InMemoryUserRepository } from '../users/in-memory-user-repository';
import { InMemoryNotificationGateway } from '../notifications/in-memory-notification-gateway';
import { CompleteTaskUseCase } from '../tasks/complete-task-use-case';
import { SendNotificationUseCase } from '../notifications/send-notification-use-case';
import { createTaskId, createUserId } from '../shared/branded-types';

describe('Task Completion Flow (Integration)', () => {
  let taskRepo: InMemoryTaskRepository;
  let userRepo: InMemoryUserRepository;
  let notificationGateway: InMemoryNotificationGateway;

  beforeEach(() => {
    taskRepo = new InMemoryTaskRepository();
    userRepo = new InMemoryUserRepository();
    notificationGateway = new InMemoryNotificationGateway();
  });

  it('deve completar task e enviar notificação', async () => {
    const userId = createUserId(1);
    const taskId = createTaskId(1);

    await userRepo.create({ id: userId, name: 'Alice' });
    await taskRepo.create({ id: taskId, ownerId: userId, estimateHours: 5, completed: false });

    const completeTask = new CompleteTaskUseCase(taskRepo, mockAudit, mockClock, logger);
    const sendNotification = new SendNotificationUseCase(notificationGateway);

    const result = await completeTask.execute(taskId, userId);
    expect(result.success).toBe(true);

    await sendNotification.execute(userId, 'Task completed!');
    const notifications = notificationGateway.getSentNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0].message).toBe('Task completed!');
  });
});
```

